import{_ as e,o as a,c as i,ag as s}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Objects & Assets","description":"","frontmatter":{},"headers":[],"relativePath":"features/objects.md","filePath":"features/objects.md"}'),r={name:"features/objects.md"};function o(n,t,l,c,d,h){return a(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="objects-assets" tabindex="-1">Objects &amp; Assets <a class="header-anchor" href="#objects-assets" aria-label="Permalink to &quot;Objects &amp; Assets&quot;">​</a></h1><p>Track rental properties, vehicles, equipment, and other business assets with full lifecycle management.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The objects module is optional. Enable it in <strong>Company &gt; Features</strong> if you don&#39;t see it in the navigation.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The objects module is designed for businesses that manage physical assets — particularly rental companies, property managers, and equipment rental services. Each object represents an asset you own or manage.</p><h2 id="object-types" tabindex="-1">Object types <a class="header-anchor" href="#object-types" aria-label="Permalink to &quot;Object types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Use case</th></tr></thead><tbody><tr><td><strong>Property</strong></td><td>Rental apartments, offices, commercial spaces</td></tr><tr><td><strong>Vehicle</strong></td><td>Cars, trucks, vans, construction vehicles</td></tr><tr><td><strong>Machine</strong></td><td>Industrial equipment, tools, generators</td></tr><tr><td><strong>Other</strong></td><td>Any other asset type</td></tr></tbody></table><h2 id="object-statuses" tabindex="-1">Object statuses <a class="header-anchor" href="#object-statuses" aria-label="Permalink to &quot;Object statuses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Description</th></tr></thead><tbody><tr><td><strong>Available</strong></td><td>Ready to be rented or used</td></tr><tr><td><strong>Rented</strong></td><td>Currently rented to a customer</td></tr><tr><td><strong>Inactive</strong></td><td>Not available (maintenance, retired)</td></tr></tbody></table><h2 id="creating-an-object" tabindex="-1">Creating an object <a class="header-anchor" href="#creating-an-object" aria-label="Permalink to &quot;Creating an object&quot;">​</a></h2><ol><li>Go to <strong>Objects &gt; New Object</strong></li><li>Fill in: <ul><li><strong>Name</strong> — A clear identifier (e.g., &quot;Apartment 3B&quot; or &quot;Excavator CAT 320&quot;)</li><li><strong>Type</strong> — Property, Vehicle, Machine, or Other</li><li><strong>Status</strong> — Available, Rented, or Inactive</li><li><strong>Description</strong> — Details about the asset</li></ul></li><li>Click <strong>Save</strong></li></ol><h2 id="object-detail-page" tabindex="-1">Object detail page <a class="header-anchor" href="#object-detail-page" aria-label="Permalink to &quot;Object detail page&quot;">​</a></h2><p>The detail page shows:</p><ul><li>Asset information and type</li><li>Current status</li><li>Linked contracts</li><li>Rental history</li><li>Associated invoices</li></ul><h2 id="linking-objects-to-contracts-and-invoices" tabindex="-1">Linking objects to contracts and invoices <a class="header-anchor" href="#linking-objects-to-contracts-and-invoices" aria-label="Permalink to &quot;Linking objects to contracts and invoices&quot;">​</a></h2><p>Objects integrate with other MyCompanyDesk features:</p><ul><li><strong>Contracts</strong> — Create a rental contract for an object, specifying the tenant (customer) and terms</li><li><strong>Invoices</strong> — Invoices can be flagged as rental invoices and linked to objects</li><li><strong>Recurring invoices</strong> — Set up automatic monthly rent invoicing per object</li></ul><h2 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h2><p>Filter your objects by:</p><ul><li><strong>Type</strong> — Property, Vehicle, Machine, Other</li><li><strong>Status</strong> — Available, Rented, Inactive</li><li><strong>Search</strong> — Find by name or description</li></ul><h2 id="bulk-actions" tabindex="-1">Bulk actions <a class="header-anchor" href="#bulk-actions" aria-label="Permalink to &quot;Bulk actions&quot;">​</a></h2><ul><li><strong>Change status</strong> — Update availability in bulk</li><li><strong>Archive</strong> — Move to archive</li><li><strong>Delete</strong> — Remove objects</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use the status filter to quickly see which assets are available for rent</li><li>Link every rental invoice to its object for complete financial tracking per asset</li><li>Set up contracts with recurrence for automatic rent invoicing</li><li>Check the object metrics at the top of the page for availability overview</li></ul>',24)])])}const g=e(r,[["render",o]]);export{u as __pageData,g as default};
